const buffer = new ArrayBuffer(4);
const intView = new Uint32Array(buffer);
const floatView = new Float32Array(buffer);
let combined = 0;
let data = {};

// helper to combine 2x 16-bit registers (little-endian word order)
function readFloatLE(lowIndex) {
    combined = ((msg.payload[lowIndex + 1] << 16) | (msg.payload[lowIndex] & 0xFFFF)) >>> 0;
    intView[0] = combined;
    return Number(floatView[0].toFixed(3));
}

const registerOffsets = {
    energyUnit: 0,              // 30101
    energyValue: 2,             // 30103-30104
    energyTariffOneValue: 4,    // 30105-30106
    energyTariffTwoValue: 6,    // 30107-30108
};

// read values
const energyUnitId = msg.payload[registerOffsets.energyUnit];
const energyValue = readFloatLE(registerOffsets.energyValue);
const energyTariffOneValue = readFloatLE(registerOffsets.energyTariffOneValue);
const energyTariffTwoValue = readFloatLE(registerOffsets.energyTariffTwoValue);

// decode units
const energyUnits = {
    19: 'kilowattHour',
    146: 'megawattHour',
    126: 'megajoule',
    226: 'gigajoule',
    147: 'kilobritishThermalUnits',
    148: 'megabritishThermalUnits',
    227: 'megacalorie',
    228: 'gigacalorie',
};

data["energyUnit"] = energyUnits[energyUnitId] || "unknown";
switch (energyUnitId) {
    case 19:
        data["energyValue"] = energyValue * 1;
        data["energyTariffOneValue"] = energyTariffOneValue * 1;
        data["energyTariffTwoValue"] = energyTariffTwoValue * 1;
        break;
    case 146:
        data["energyValue"] = energyValue * 1000;
        data["energyTariffOneValue"] = energyTariffOneValue * 1000;
        data["energyTariffTwoValue"] = energyTariffTwoValue * 1000;
        break;
    case 126:
        data["energyValue"] = energyValue / 3.6;
        data["energyTariffOneValue"] = energyTariffOneValue * 3.6;
        data["energyTariffTwoValue"] = energyTariffTwoValue * 3.6;
        break;
    case 226:
        data["energyValue"] = energyValue * 277.777778;
        data["energyTariffOneValue"] = energyTariffOneValue * 277.777778;
        data["energyTariffTwoValue"] = energyTariffTwoValue * 277.777778;
        break;
    case 147:
        data["energyValue"] = energyValue * 0.293071;
        data["energyTariffOneValue"] = energyTariffOneValue * 0.293071;
        data["energyTariffTwoValue"] = energyTariffTwoValue * 0.293071;
        break;
    case 148:
        data["energyValue"] = energyValue * 293.071;
        data["energyTariffOneValue"] = energyTariffOneValue * 293.071;
        data["energyTariffTwoValue"] = energyTariffTwoValue * 293.071;
        break;
    case 227:
        data["energyValue"] = energyValue * 1.162222;
        data["energyTariffOneValue"] = energyTariffOneValue * 1.162222;
        data["energyTariffTwoValue"] = energyTariffTwoValue * 1.162222;
        break;
    case 228:
        data["energyValue"] = energyValue * 1162.222;
        data["energyTariffOneValue"] = energyTariffOneValue * 1162.222;
        data["energyTariffTwoValue"] = energyTariffTwoValue * 1162.222;
        break;

    default:
        break;
}

let nmsg = {};
nmsg.topic = "telemetry";
nmsg.payload = data;

return nmsg;

