    volumeValue: 2,   // 30303-30304
};

// read values
const volumeUnitId = msg.payload[registerOffsets.volumeUnit];
const volumeValue = readFloatLE(registerOffsets.volumeValue);

// decode units
const volumeUnits = {
    80: 'cubicMetre',
    82: 'litre',
    83: 'usGallon',
    229: 'thousandUsGallons',
};

data["volumeUnit"] = volumeUnits[volumeUnitId] || "unknown";
