const buffer = new ArrayBuffer(4);
const intView = new Uint32Array(buffer);
const floatView = new Float32Array(buffer);
let combined = 0;
let data = {};

// helper to combine 2x 16-bit registers (little-endian word order)
function readFloatLE(lowIndex) {
    combined = ((msg.payload[lowIndex + 1] << 16) | (msg.payload[lowIndex] & 0xFFFF)) >>> 0;
    intView[0] = combined;
    return Number(floatView[0].toFixed(3));
}

const registerOffsets = {
    tempUnit: 0,      // 30721
    tempHighValue: 2, // 30723-30724
    tempLowValue: 4   // 30725-30726
};

// read values
const tempUnitId = msg.payload[registerOffsets.tempUnit];
const tempHighValue = readFloatLE(registerOffsets.tempHighValue);
const tempLowValue = readFloatLE(registerOffsets.tempLowValue);

// decode units
const tempUnits = {
    62: 'celsius',
};

data["tempUnit"] = tempUnits[tempUnitId] || "unknown";
switch (tempUnitId) {
    case 62:
        data["tempHighValue"] = tempHighValue * 1;
        data["tempLowValue"] = tempLowValue * 1;
        break;

    default:
        break;
}

let nmsg = {};
nmsg.topic = "telemetry";
nmsg.payload = data;

return nmsg;

// Haal de globale MID variabele op (message ID)
let mid = global.get("mid"); // NaN if not set

// Stel de constante Dev in
const Dev = "ASSET_ID_START_MET_36";

// Definieer de mapping van datatypes naar ID's
const idMapping = {
    "energyValue": 9600,
    "energyTariffOneValue": 9601,
    "energyTariffTwoValue": 9602,
    "volumeValue": 9650,
    "tempHighValue": 9700,
    "tempLowValue": 9750,
};

//Maak mapping case-insensitive door keys ook in lowercase aan te spreken
const mappingLower = {};
Object.keys(idMapping).forEach(k => mappingLower[k.toLowerCase()] = idMapping[k]);

// Begin met het resultaat-object
let result = {
    MID: mid,
    D: [
        {
            Dev: Dev,
            ED: [],
            MD: []
        }
    ]
};

// Payload van binnenkomend bericht
const payloadData = msg.payload || {};
if (typeof payloadData !== "object") {
    node.warn("msg.payload is geen object");
}

// Vind de device objecten
const deviceObjects = Object.values(payloadData).filter(
    v => v && typeof v === "object" && !Array.isArray(v)
);

// Loop door payload keys
deviceObjects.forEach((devObj, devIdx) => {
    Object.keys(devObj).forEach(key => {
        let id = idMapping[key];
        if (typeof id === "undefined") {
            id = mappingLower[key.toLowerCase()];
        }

        if (typeof id !== "undefined") {
            // Zorg dat de waarde een getal wordt: vervang komma -> punt en parse
            let rawVal = devObj[key];

            // Als waarde een array / object / null is, skip
            if (rawVal === null || typeof rawVal === "object") {
                node.warn(`Overslaan ${key}: waarde is geen primitief (${typeof rawVal}) [deviceIdx=${devIdx}]`);
                return; // return i.p.v. continue (we zitten in forEach)
            }

            let valStr = String(rawVal).trim().replace(",", ".");
            let num = parseFloat(valStr);

            if (!Number.isFinite(num)) {
                node.warn(`Ongeldige numerieke waarde voor ${key}: "${rawVal}" — overslaan [deviceIdx=${devIdx}]`);
                return;
            }

            result.D[0].MD.push({
                Id: id,
                Val: num
            });

        } else {
            node.debug(`Key niet in mapping: ${key} [deviceIdx=${devIdx}]`);
        }
    });
});

// Voeg een timestamp toe in het juiste formaat
result.D[0].TS = new Date().toISOString();

// Alleen verhogen als we items toegevoegd hebben
if (result.D[0].MD.length > 0) {
    global.set("mid", mid + 1);
}

// Stel de nieuwe payload in
msg.payload = result;

return msg;
